content.problemStatement:
Chef loves to cook pies. But more than that, he loves to play with numbers. And this task is one of his favorites. The goal is very simple: you need to select **3** numbers from an array of **N** numbers, such that their **XOR** will be maximal.

**XOR** - exclusive or (**xor** - in Pascal, **^** - in C++) 

&nbsp;

code.C:
#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int arr[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &arr[i]);
        }
        int max_xor = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                for (int k = j + 1; k < N; k++) {
                    int xor = arr[i] ^ arr[j] ^ arr[k];
                    max_xor = (max_xor > xor) ? max_xor : xor;
                }
            }
        }
        printf("%d\n", max_xor);
    }
    return 0;
}

