    while (T--) {
        int N;
        cin >> N;
        int arr[N];
        for (int i = 0; i < N; i++) {
            cin >> arr[i];
        }
        int max_xor = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                for (int k = j + 1; k < N; k++) {
                    int xor = arr[i] ^ arr[j] ^ arr[k];
                    max_xor = max(max_xor, xor);
                }
            }
        }
        cout << max_xor << endl;
    }
    return 0;
}

code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] arr = new int[N];
            for (int i = 0; i < N; i++) {
                arr[i] = sc.nextInt();
            }
            int max_xor = 0;
            for (int i = 0; i < N; i++) {
                for (int j = i + 1; j < N; j++) {
                    for (int k = j + 1; k < N; k++) {
                        int xor = arr[i] ^ arr[j] ^ arr[k];
                        max_xor = Math.max(max_xor, xor);
                    }
                }
            }
            System.out.println(max_xor);
        }
    }
}

